import React from 'react';
import clsx from 'clsx';
import { ColorInput } from './ColorInput';
import { ColorPickerChangeSource, HrgbKey } from '../type';
import { COLORKEY, RGBKEY } from '../const';
import { useColorPickerContextSelector } from '../ColorPickerContext';

export const Panel = React.forwardRef<HTMLDivElement, React.ComponentPropsWithoutRef<'div'>>(
  ({ className, ...props }, ref) => {
    const setValue = useColorPickerContextSelector(o => o.setValue);
    const rootCssScope = useColorPickerContextSelector(o => o.rootCssScope);
    const rgb = useColorPickerContextSelector(o => o.rgb);
    const hex = useColorPickerContextSelector(o => o.hex);
    const prefix = rootCssScope('-panel');

    const handleChange = (key: HrgbKey, val: string | number) => {
      if (RGBKEY.includes(key)) {
        const newRgb = Object.assign({}, rgb, { [key]: val });
        setValue(newRgb, { source: ColorPickerChangeSource.INPUT });
        return;
      }
      setValue(val.toString(), { source: ColorPickerChangeSource.INPUT });
    };

    const renderRgbInput = () =>
      COLORKEY.map(key => {
        const curKeyColor = key === HrgbKey.HEX ? hex : rgb[key];
        return <ColorInput colorKey={key} key={key} color={curKeyColor} onChange={handleChange} />;
      });

    return (
      <div {...props} className={clsx(prefix, className)} ref={ref}>
        {renderRgbInput()}
      </div>
    );
  },
);
